class ColorPickerDialog:
    """Color picker with clickable palette and hex entry, position-aware."""

    def __init__(
        self,
        parent: tk.Toplevel,
        *,
        title: str = "Choose color",
        initial_color: str = "#000000",
        on_choose: Callable[[str], None],
        position_x: int | None = None,
        position_y: int | None = None,
        on_position_save: Callable[[int, int], None] | None = None,
    ):
        self._on_choose = on_choose
        self._on_position_save = on_position_save

        self._window = tk.Toplevel(parent)
        self._window.title(title)
        self._window.configure(bg=_CHROME_BG)
        self._window.resizable(False, False)
        self._window.wm_attributes("-topmost", True)
        self._window.transient(parent)

        # Restore saved position, or offset from parent
        if position_x is not None and position_y is not None:
            self._window.geometry(f"+{position_x}+{position_y}")
        else:
            try:
                px = parent.winfo_x() + 40
                py = parent.winfo_y() + 40
                self._window.geometry(f"+{px}+{py}")
            except tk.TclError:
                pass

        frame = tk.Frame(self._window, bg=_CHROME_BG, padx=12, pady=10)
        frame.pack(fill=tk.BOTH, expand=True)

        # Color palette grid
        palette_frame = tk.Frame(frame, bg=_CHROME_BG)
        palette_frame.grid(row=0, column=0, columnspan=2, pady=(0, 8))
        for row_idx, row_colors in enumerate(_PALETTE):
            for col_idx, color in enumerate(row_colors):
                swatch = tk.Label(
                    palette_frame,
                    bg=color,
                    width=2,
                    height=1,
                    relief=tk.RAISED,
                    cursor="hand2",
                )
                swatch.grid(row=row_idx, column=col_idx, padx=1, pady=1)
                swatch.bind("<Button-1>", self._make_swatch_handler(color))

        # Preview swatch
        self._preview = tk.Label(frame, width=20, height=2, bg=initial_color, relief=tk.SUNKEN)
        self._preview.grid(row=1, column=0, columnspan=2, pady=(0, 6))

        # Hex entry row
        hex_frame = tk.Frame(frame, bg=_CHROME_BG)
        hex_frame.grid(row=2, column=0, columnspan=2, sticky=tk.W)

        tk.Label(hex_frame, text="Hex:", bg=_CHROME_BG, fg=_CHROME_FG, font=_CHROME_FONT).pack(
            side=tk.LEFT, padx=(0, 4)
        )

        self._hex_var = tk.StringVar(value=initial_color)
        self._hex_entry = tk.Entry(
            hex_frame, textvariable=self._hex_var, width=10, font=_CHROME_FONT
        )
        self._hex_entry.pack(side=tk.LEFT)
        self._hex_entry.select_range(0, tk.END)
        self._hex_entry.focus_set()

        self._hex_var.trace_add("write", self._on_hex_change)

        # Error label
        self._error_label = tk.Label(
            frame, text="", bg=_CHROME_BG, fg="#ff6666", font=(_FONT_FAMILY, 7)
        )
        self._error_label.grid(row=3, column=0, columnspan=2, sticky=tk.W)

        # Buttons
        btn_frame = tk.Frame(frame, bg=_CHROME_BG)
        btn_frame.grid(row=4, column=0, columnspan=2, pady=(6, 0), sticky=tk.E)
        tk.Button(btn_frame, text="Cancel", command=self._on_cancel, width=8).pack(
            side=tk.RIGHT, padx=(4, 0)
        )
        tk.Button(btn_frame, text="OK", command=self._on_ok, width=8).pack(side=tk.RIGHT)

        self._window.bind("<Return>", lambda e: self._on_ok())
        self._window.bind("<Escape>", lambda e: self._on_cancel())

    def _make_swatch_handler(self, color: str):
        def handler(event):
            self._hex_var.set(color)
            self._preview.configure(bg=color)
            self._error_label.configure(text="")

        return handler

    def _on_hex_change(self, *_args):
        value = self._hex_var.get().strip()
        if not value.startswith("#"):
            value = "#" + value
        if _HEX_COLOR_RE.match(value):
            try:
                self._preview.configure(bg=value)
                self._error_label.configure(text="")
            except tk.TclError:
                self._error_label.configure(text="Invalid color")
        else:
            self._error_label.configure(text="Format: #RRGGBB")

    def _save_position(self):
        if self._on_position_save:
            try:
                self._on_position_save(self._window.winfo_x(), self._window.winfo_y())
            except tk.TclError:
                pass

    def _on_ok(self):
        value = self._hex_var.get().strip()
        if not value.startswith("#"):
            value = "#" + value
        if _HEX_COLOR_RE.match(value):
            self._save_position()
            self._on_choose(value)
            self._window.destroy()

    def _on_cancel(self):
        self._save_position()
        self._window.destroy()
